@function ms-grid($units, $ratio)
      $column-sum: 100%
      $grid-sum: 0%
      $column-ratio: $ratio
      $return: 0
      $column-short: false
      @if $ratio > 1
        $column-ratio: 1 / $ratio
      @for $i from 1 through $units
        $column-sum: ms($i, 100%, $column-ratio)
        $grid-sum: $column-sum + $grid-sum
        $return: $column-sum
        @if $grid-sum > 100%
          $return: 0%
          @if $column-short == false
            $column-short: $i
        @if $i == $columns
          @if $grid-sum < 100%
            $return: 100% - $grid-sum + $column-sum
        @if $column-short == $i
          $return: 100% - $grid-sum + $column-sum
      @return $return

